/* WARNING: Script requires that SQLITE_DBCONFIG_DEFENSIVE be disabled */
PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE nodes (
    id TEXT PRIMARY KEY,
    text TEXT NOT NULL,
    status TEXT DEFAULT 'todo',
    metadata JSON DEFAULT '{}',
    alias TEXT,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    -- Virtual columns for O(1) metadata filtering (Tier 1)
    priority INTEGER GENERATED ALWAYS AS (json_extract(metadata, '$.priority')) VIRTUAL,
    type TEXT GENERATED ALWAYS AS (json_extract(metadata, '$.type')) VIRTUAL
);
INSERT INTO nodes VALUES('wv-2731e7','Update copilot-instructions template — enforcement gap, 4-MCP requirement, quality/recover commands','done',replace('{\n  "commits": [\n    "e3f9e2c",\n    "257996c",\n    "92b26c4"\n  ]\n}','\n',char(10)),NULL,'2026-03-05 17:56:14','2026-03-05 18:01:30');
INSERT INTO nodes VALUES('wv-8b2926','Update copilot-instructions template and sync to public repo','done',replace('{\n  "learning": "pitfall: must run ./install.sh before wv-init-repo --update to pick up template changes — installed binary has stale heredoc otherwise",\n  "learning_hygiene": 4,\n  "commits": [\n    "257996c"\n  ]\n}','\n',char(10)),NULL,'2026-03-05 17:57:16','2026-03-05 18:01:26');
CREATE TABLE edges (
    source TEXT NOT NULL,
    target TEXT NOT NULL,
    type TEXT NOT NULL CHECK(type IN ('blocks', 'relates_to', 'implements', 'contradicts', 'supersedes', 'references', 'obsoletes', 'addresses')),
    weight REAL DEFAULT 1.0,
    context JSON DEFAULT '{}',
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY(source, target, type),
    FOREIGN KEY(source) REFERENCES nodes(id),
    FOREIGN KEY(target) REFERENCES nodes(id)
);
PRAGMA writable_schema=ON;
INSERT INTO sqlite_schema(type,name,tbl_name,rootpage,sql)VALUES('table','nodes_fts','nodes_fts',0,'CREATE VIRTUAL TABLE nodes_fts USING fts5(
